// item[0] = sea forecast   { data: [{globalIdLocal, latitude, longitude, waveHighMin, waveHighMax, sstMin, sstMax, ...}] }
// item[1] = weather stations { data: [{globalIdLocal, latitude, longitude, local, ...}] }

const all = $input.all();
const seaItem      = all.find(i => i.json.data?.[0]?.waveHighMin != null);
const stationsItem = all.find(i => i.json.data?.[0]?.globalIdLocal != null && i.json.data?.[0]?.waveHighMin == null);

if (!seaItem)      throw new Error('Sea forecast data missing — check Previsão do Mar node');
if (!stationsItem) throw new Error('Weather stations data missing — check Estações IPMA node');

const seaStations     = seaItem.json.data      ?? [];
const weatherStations = stationsItem.json.data ?? [];

// Log a sea station sample so you can verify field names in n8n output panel
console.log('Sea station sample:', JSON.stringify(seaStations[0]));

function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(lat1 * Math.PI / 180) *
    Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.asin(Math.sqrt(a));
}

// Safe average: returns null if either value is null/undefined/NaN
function avg(a, b) {
  if (a == null || b == null || isNaN(a) || isNaN(b)) return null;
  return Math.round((a + b) / 2 * 10) / 10;
}

// Safe SQL value: converts null, undefined, and NaN all to SQL NULL
function v(r) {
  return (r == null || (typeof r === 'number' && isNaN(r))) ? 'NULL' : r;
}

const rows = [];

for (const ws of weatherStations) {
  const wsLat = parseFloat(ws.latitude);
  const wsLon = parseFloat(ws.longitude);
  if (isNaN(wsLat) || isNaN(wsLon)) continue;

  let nearest = null, minDist = Infinity;
  for (const ss of seaStations) {
    const d = haversine(wsLat, wsLon, ss.latitude, ss.longitude);
    if (d < minDist) { minDist = d; nearest = ss; }
  }
  if (!nearest) continue;

  // All IPMA sea forecast values are strings — parseFloat before arithmetic
  rows.push({
    ipma_global_id  : ws.globalIdLocal,
    temp_agua       : avg(parseFloat(nearest.sstMin), parseFloat(nearest.sstMax)),
    ondulacao_altura: nearest.waveHighMax != null ? parseFloat(nearest.waveHighMax) : null,
  });
}

console.log(`Built ${rows.length} update rows. Sample:`, JSON.stringify(rows[0]));
if (rows.length === 0) throw new Error('No rows produced — check sea station data format');

const values = rows
  .map(r => `(${r.ipma_global_id}, ${v(r.temp_agua)}, ${v(r.ondulacao_altura)})`)
  .join(',\n');

const sql = `
UPDATE meteo_diario AS m
SET
  temp_agua        = v.temp_agua::decimal,
  ondulacao_altura = v.ondulacao::decimal
FROM (
  VALUES ${values}
) AS v(ipma_global_id, temp_agua, ondulacao)
WHERE m.ipma_global_id = v.ipma_global_id::integer
  AND m.data = CURRENT_DATE
`;

return [{ json: { sql, total: rows.length } }];
